using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// The SDK injects HttpClient and ILogger via constructor DI — these
/// never appear in the tool schema that the LLM sees.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Get a post by its numeric ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<Post>(
            $"/posts/{id}", cancellationToken);
        return $"Title: {post!.Title}\n\n{post.Body}";
    }

    [McpServerTool, Description("List posts for a specific user.")]
    public async Task<string> GetUserPosts(
        [Description("The user ID to filter by")] int userId,
        CancellationToken cancellationToken = default)
    {
        var posts = await httpClient.GetFromJsonAsync<Post[]>(
            $"/posts?userId={userId}", cancellationToken);
        return string.Join("\n", posts!.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Search comments on a specific post.")]
    public async Task<string> GetPostComments(
        [Description("The post ID to get comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        var comments = await httpClient.GetFromJsonAsync<Comment[]>(
            $"/posts/{postId}/comments", cancellationToken);
        return string.Join("\n\n", comments!.Select(c =>
            $"From: {c.Email}\n{c.Body}"));
    }
}

public record Post(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

public record Comment(
    [property: JsonPropertyName("postId")] int PostId,
    [property: JsonPropertyName("email")] string Email,
    [property: JsonPropertyName("body")] string Body);

